const requestId = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (char) => {
  const random = Math.floor(Math.random() * 16);
  const value = char === 'x' ? random : (random & 0x3) | 0x8;
  return value.toString(16);
});
return [{
  json: {
    contract_version: '1.0',
    request_id: requestId,
    triggered_by: 'n8n_manual',
    mode: 'incremental',
    source: 'cowrie_ndjson'
  }
}];

const required = ['contract_version', 'request_id', 'status', 'events_read', 'events_inserted', 'events_indexed', 'errors_count'];
for (const item of $input.all()) {
  for (const field of required) {
    if (!(field in item.json)) throw new Error(`INVALID_WORKER_RESULT: missing ${field}`);
  }
  if (item.json.contract_version !== '1.0') throw new Error('INVALID_WORKER_RESULT: contract version');
  if (item.json.status !== 'completed') throw new Error(`PIPELINE_FAILED: ${item.json.error_code || 'unknown'}`);
}
return $input.all();

const items = $input.all();
if (items.length !== 1) throw new Error('PIPELINE_RUN_NOT_FOUND');
const run = items[0].json;
if (run.status !== 'completed' || Number(run.errors_count) !== 0) {
  throw new Error(`PIPELINE_RUN_INVALID: ${run.status}`);
}
return items;
